const inputItem = $input.first();
const output    = inputItem.json.output || inputItem.json.text || '';
// ── Parse JSON from agent output ────────────────────────────────────────────
let parsed = null;
const fence = output.match(/```json\s*([\s\S]*?)```/);
if (fence) { try { parsed = JSON.parse(fence[1].trim()); } catch(e) {} }
if (!parsed) { const b = output.match(/\{[\s\S]+\}/); if (b) { try { parsed = JSON.parse(b[0]); } catch(e) {} } }
if (!parsed) { try { parsed = JSON.parse(output.trim()); } catch(e) {} }
function clean(v) {
 if (!v) return '';
 const s = String(v).trim();
 return (s === 'null' || s === 'undefined' || s === 'skip') ? '' : s;
}
const ready         = parsed !== null && parsed.ready === true;
const promptName    = clean(parsed?.prompt_name);
const testQuestion  = clean(parsed?.test_question);
const expectedTable = clean(parsed?.expected_table).toUpperCase();
const rawCols       = clean(parsed?.expected_columns);
const expectedCols  = rawCols ? rawCols.split(',').map(c => c.trim().toUpperCase()).filter(Boolean) : [];
const variants      = Array.isArray(parsed?.variants) ? parsed.variants : [];
const intakeTokens  = parsed?.input_tokens || 0;
if (!ready || !promptName) {
 return [{ json: { ready: false, agent_message: output } }];
}
// ── Get YAML from static data ────────────────────────────────────────────────
const sd = $getWorkflowStaticData('global');
let yamlContent = inputItem.json.yaml_content || sd['yaml_content'] || '';
yamlContent = yamlContent.replace(/\\n/g, '\n').replace(/\\t/g, '\t');
if (!yamlContent) {
 throw new Error('yaml_content is empty. Make sure Node 1 ran successfully this session.');
}
// ── Extract prompt_content — this becomes the system prompt for Node 7 ───────
function extractPromptContent(yaml, name) {
 const lines      = yaml.split('\n');
 let foundEntry   = false;
 let inContent    = false;
 let baseIndent   = -1;
 const result     = [];
 for (let i = 0; i < lines.length; i++) {
   const line = lines[i];
   const nameMatch = line.match(/^\s*-?\s*prompt_name\s*:\s*(.+)$/);
   if (nameMatch) {
     const entryName = nameMatch[1].trim().replace(/^["']|["']$/g, '');
     if (foundEntry && inContent && result.length > 0) {
       return result.join('\n').trim();
     }
     foundEntry    = (entryName === name);
     inContent     = false;
     baseIndent    = -1;
     result.length = 0;
     continue;
   }
   if (!foundEntry) continue;
   const contentBlockMatch  = line.match(/^(\s*)prompt_content\s*:\s*[|>][-+]?\s*$/);
   const contentInlineMatch = line.match(/^(\s*)prompt_content\s*:\s*(\S.+)$/);
   if (contentBlockMatch)  { inContent = true; baseIndent = -1; continue; }
   if (contentInlineMatch) { return contentInlineMatch[2].trim().replace(/^["']|["']$/g, ''); }
   if (!inContent) continue;
   const lineIndent = line.match(/^(\s*)/)[1].length;
   if (baseIndent === -1) {
     if (line.trim() === '') continue;
     baseIndent = lineIndent;
   }
   if (line.trim() !== '' && lineIndent < baseIndent) break;
   result.push(line.length >= baseIndent ? line.slice(baseIndent) : line.trim());
 }
 if (foundEntry && inContent && result.length > 0) return result.join('\n').trim();
 return null;
}
const systemPrompt = extractPromptContent(yamlContent, promptName);
if (!systemPrompt) {
 const foundNames = yamlContent.split('\n')
   .map(l => { const m = l.match(/^\s*-?\s*prompt_name\s*:\s*(.+)$/); return m ? m[1].trim().replace(/^["']|["']$/g,'') : null; })
   .filter(Boolean);
 throw new Error(`Prompt "${promptName}" not found. Names found: [${foundNames.join(', ')}]`);
}
// ── Build output items ───────────────────────────────────────────────────────
// NOTE: yaml_content is intentionally excluded from output.
// Node 7 only needs system_prompt (the extracted prompt_content) and the
// variant_question as user message. Passing the full YAML downstream
// would blow the model's context window.
sd['current_test_results'] = [];
sd['current_test_context']  = null;
const runId = 'run_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);
const base = {
 run_id:           runId,
 submitted_at:     new Date().toISOString(),
 prompt_name:      promptName,
 test_question:    testQuestion,
 expected_table:   expectedTable,
 expected_columns: expectedCols,
 system_prompt:    systemPrompt,   // ← full prompt_content from YAML, used as Node 7 system prompt
 intake_tokens:    intakeTokens
 // yaml_content deliberately not included — stored in static data only
};
sd['current_test_context'] = base;
const finalVariants = variants.length === 3
 ? variants
 : [testQuestion, testQuestion, testQuestion];
return finalVariants.map((q, i) => ({
 json: {
   ...base,
   variant_index:    i + 1,
   variant_question: q       // ← this is the user prompt for Node 7
 }
}));

const item       = $input.first();
const chatInput  = item.json.chatInput || '';
const binaryData = item.binary;
const sd         = $getWorkflowStaticData('global');
const hasFile = binaryData && Object.keys(binaryData).length > 0;
// ── No file attached — try to reuse previously stored YAML ──────────────────
if (!hasFile) {
 const cachedYaml   = sd['yaml_content'];
 const cachedPrompts = sd['available_prompts'];
 if (cachedYaml && cachedPrompts && cachedPrompts.length > 0) {
   // Reuse stored YAML silently
   return [{ json: {
     chatInput,
     available_prompts: cachedPrompts,
     file_error:        null,
     yaml_source:       'cache'   // helpful for debugging
   }}];
 }
 // Nothing stored yet — ask user to upload
 return [{ json: {
   chatInput,
   available_prompts: [],
   file_error:        'No YAML file loaded. Please upload your YAML prompts file to begin.',
   yaml_source:       'none'
 }}];
}
// ── File attached — parse and store, replacing any previous YAML ─────────────
const fileKey = Object.keys(binaryData)[0];
const b64     = binaryData[fileKey].data;
if (!b64) {
 return [{ json: {
   chatInput,
   available_prompts: [],
   file_error:        'File was attached but could not be read. Please try uploading again.',
   yaml_source:       'none'
 }}];
}
const yamlText = Buffer.from(b64, 'base64').toString('utf-8');
const promptNames = [];
const lines = yamlText.split('\n');
for (const line of lines) {
 const match = line.match(/^\s*-?\s*prompt_name\s*:\s*(.+)$/);
 if (match) {
   const name = match[1].trim().replace(/^["']|["']$/g, '');
   if (name) promptNames.push(name);
 }
}
if (promptNames.length === 0) {
 return [{ json: {
   chatInput,
   available_prompts: [],
   file_error:        'YAML parsed but no prompt_name fields found. Check your file structure.',
   yaml_source:       'none'
 }}];
}
// Persist to static data for all future runs
sd['yaml_content']      = yamlText;
sd['available_prompts'] = promptNames;
return [{ json: {
 chatInput,
 available_prompts: promptNames,
 file_error:        null,
 yaml_source:       'uploaded'   // so you can confirm a fresh upload was processed
}}];

const prev = $input.first().json;

const raw  = prev.output || '';

function extractSQL(txt) {
  const stripped = txt.replace(/```sql|```/gi, '').trim();
  return stripped || txt.trim();
}

const sql = extractSQL(raw).replace(/\\n/g, '\n').replace(/\\t/g, '\t');
const up  = sql.toUpperCase();
const violations = [];

if (/\bLIMIT\b/.test(up))               violations.push('Uses LIMIT (use SELECT TOP)');
if (/\bFETCH\b/.test(up))               violations.push('Uses FETCH (use SELECT TOP)');
if (/\bOFFSET\b/.test(up))              violations.push('Uses OFFSET');
if (/`/.test(sql))                       violations.push('Uses backticks');
if (/\[|\]/.test(sql))                   violations.push('Uses square brackets');
if (/!=/.test(sql))                      violations.push('Uses != (use <>)');
if (/\bISNULL\s*\(/.test(up))           violations.push('Uses ISNULL() (use COALESCE)');
if (/SELECT\s+\*/.test(up))             violations.push('Uses SELECT *');
if (/WHERE.*ROW_NUMBER\s*\(/i.test(sql)) violations.push('Filters window fn in WHERE (use QUALIFY)');

const expTable    = (prev.expected_table || '').toUpperCase();
const expCols     = prev.expected_columns || [];
const tableFound  = expTable ? up.includes(expTable) : null;
const missingCols = expCols.filter(c => c && !up.includes(c));

if (expTable && !tableFound) violations.push('Wrong table: ' + expTable);
if (missingCols.length > 0)  violations.push('Missing cols: ' + missingCols.join(', '));

// Tokens reliably set by Node 5b
const inputTokens  = parseInt(prev.input_tokens  || 0, 10);
const outputTokens = parseInt(prev.output_tokens || 0, 10);

const result = {
  variant_index:    prev.variant_index,
  variant_question: prev.variant_question,
  generated_sql:    sql,
  syntax_passed:    violations.length === 0,
  violation_count:  violations.length,
  violations:       violations,
  table_check:      tableFound === null ? 'skipped' : tableFound ? 'pass' : 'fail',
  column_check:     missingCols.length === 0 ? 'pass' : 'fail',
  mcp_answer:       '—',
  input_tokens:     inputTokens,
  output_tokens:    outputTokens
};

const sd = $getWorkflowStaticData('global');
if (!Array.isArray(sd['current_test_results'])) sd['current_test_results'] = [];
sd['current_test_results'].push(result);

return [{ json: { ...prev, latest_result: result } }];

// Token estimation for agent node output
// Agent nodes don't expose real token counts — estimate from character counts (chars/4)
const item = $input.first();
const data = item.json;

function pickInt(v) { const n = parseInt(v, 10); return isNaN(n) ? 0 : n; }

// Try real metadata first (in case future n8n version passes it through)
const meta = data.usageMetadata || {};
let inputTokens  = pickInt(meta.inputTokenCount  || meta.input_tokens  || meta.promptTokens     || 0);
let outputTokens = pickInt(meta.outputTokenCount || meta.output_tokens || meta.completionTokens || 0);

// Fall back to character-based estimation
if (!inputTokens) {
  const promptChars = (
    (data.system_prompt      || '') +
    (data.variant_question   || '')
  ).length;
  inputTokens = Math.round(promptChars / 4);
}

if (!outputTokens) {
  const outputChars = (data.output || '').length;
  outputTokens = Math.round(outputChars / 4);
}

return [{
  json: {
    ...data,
    input_tokens:  inputTokens,
    output_tokens: outputTokens
  }
}];

const sd      = $getWorkflowStaticData('global');
const results = Array.isArray(sd['current_test_results']) ? sd['current_test_results'] : [];
const ctx     = sd['current_test_context'] || {};
delete sd['current_test_results'];
delete sd['current_test_context'];
// ── Consistency check — same tables used across all 3 SQLs ──────────────────
const tablesUsed = results.map(r => {
 const matches = (r.generated_sql || '').match(/FROM\s+([\w.]+)|JOIN\s+([\w.]+)/gi) || [];
 return matches.map(m => m.replace(/FROM\s+|JOIN\s+/i, '').trim().toUpperCase()).sort().join(',');
});
const allSameTables    = new Set(tablesUsed).size === 1;
const consistencyScore = allSameTables ? 90 : 50;
const consistencyVerdict = allSameTables ? 'PASS' : 'WARN';
// ── Aggregate syntax results ─────────────────────────────────────────────────
const allV   = results.flatMap(v => v.violations || []);
const uniqV  = [...new Set(allV)];
const totV   = results.reduce((s, v) => s + (v.violation_count || 0), 0);
const synOK  = results.length > 0 && results.every(v => v.syntax_passed);
const tblChk = results.length > 0 && results.every(v => v.table_check === 'pass' || v.table_check === 'skipped') ? 'pass' : 'fail';
const colChk = results.length > 0 && results.every(v => v.column_check === 'pass') ? 'pass' : 'skipped';
const inTok  = results.reduce((s, v) => s + (v.input_tokens  || 0), 0) + (ctx.intake_tokens || 0);
const outTok = results.reduce((s, v) => s + (v.output_tokens || 0), 0);
const verdict =
 (!synOK || tblChk === 'fail') ? 'FAIL' :
 (consistencyVerdict === 'WARN') ? 'WARN' :
 synOK ? 'PASS' : 'WARN';
const v = results;
return [{ json: {
 // ── Run metadata ────────────────────────────────────────────────────────
 run_id:               ctx.run_id,
 tested_at:            new Date().toISOString(),
 prompt_name:          ctx.prompt_name,
 seed_question:        ctx.test_question,
 expected_table:       ctx.expected_table   || '-',
 expected_columns:     (ctx.expected_columns || []).join(', ') || '-',
 // ── Overall verdict ─────────────────────────────────────────────────────
 final_verdict:        verdict,
 consistency_score:    consistencyScore + '/100',
 consistency_verdict:  consistencyVerdict,
 syntax_all_passed:    synOK ? '✅ Yes' : '❌ No',
 syntax_violations:    uniqV.join(' | ') || '-',
 table_check:          tblChk,
 column_check:         colChk,
 // ── Token usage ─────────────────────────────────────────────────────────``
 total_input_tokens:   inTok,
 total_output_tokens:  outTok,
 total_tokens:         inTok + outTok,
 // ── Variant 1 ───────────────────────────────────────────────────────────
 variant_1_question:   v[0]?.variant_question || '-',
 variant_1_sql:        v[0]?.generated_sql    || '-',
 variant_1_mcp_answer: v[0]?.mcp_answer       || '-',
 // ── Variant 2 ───────────────────────────────────────────────────────────
 variant_2_question:   v[1]?.variant_question || '-',
 variant_2_sql:        v[1]?.generated_sql    || '-',
 variant_2_mcp_answer: v[1]?.mcp_answer       || '-',
 // ── Variant 3 ───────────────────────────────────────────────────────────
 variant_3_question:   v[2]?.variant_question || '-',
 variant_3_sql:        v[2]?.generated_sql    || '-',
 variant_3_mcp_answer: v[2]?.mcp_answer       || '-',
}}];

const sd  = $getWorkflowStaticData('global');
const row = $input.first().json;
if (!Array.isArray(sd['csv_rows'])) sd['csv_rows'] = [];
sd['csv_rows'].push(row);
const total = sd['total_questions'] || 1;
const done  = sd['csv_rows'].length >= total;
if (!done) return [];
const rows = sd['csv_rows'];
delete sd['csv_rows'];
const headers = [
  'run_id','tested_at','prompt_name','seed_question',
  'expected_table','expected_columns',
  'final_verdict','consistency_score','consistency_verdict',
  'syntax_all_passed','syntax_violations','table_check','column_check',
  'total_input_tokens','total_output_tokens','total_tokens',
  'variant_1_question','variant_1_sql','variant_1_mcp_answer',
  'variant_2_question','variant_2_sql','variant_2_mcp_answer',
  'variant_3_question','variant_3_sql','variant_3_mcp_answer',
  'recommend_issues','recommend_improvements','recommend_reasoning'
];
function esc(v) {
  if (v === null || v === undefined) return '';
  const s = String(v).replace(/"/g, '""');
  return '"' + s + '"';
}
const csvLines = [headers.join(',')];
for (const r of rows) {
  csvLines.push(headers.map(h => esc(r[h])).join(','));
}
const csvContent = csvLines.join('\n');
const base64     = Buffer.from(csvContent, 'utf-8').toString('base64');
return [{
  json: { message: `✅ Done! ${rows.length} questions tested.`, row_count: rows.length },
  binary: {
    data: {
      data:          base64,
      mimeType:      'text/csv',
      fileName:      `sql_test_results_${new Date().toISOString().slice(0,10)}.csv`,
      fileExtension: 'csv'
    }
  }
}];

const item = $input.first().json;
const sd   = $getWorkflowStaticData('global');

// Store full summary so Node 7d can recover it after chainLlm swallows fields
sd['pending_summary'] = item;

const yamlContent = (sd['yaml_content'] || '').replace(/\\n/g, '\n').replace(/\\t/g, '\t');

function extractPromptContent(yaml, name) {
  const lines = yaml.split('\n');
  let foundEntry = false, inContent = false, baseIndent = -1;
  const result = [];
  for (const line of lines) {
    const nameMatch = line.match(/^\s*-?\s*prompt_name\s*:\s*(.+)$/);
    if (nameMatch) {
      const entryName = nameMatch[1].trim().replace(/^["']|["']$/g, '');
      if (foundEntry && inContent && result.length > 0) return result.join('\n').trim();
      foundEntry = (entryName === name);
      inContent = false; baseIndent = -1; result.length = 0;
      continue;
    }
    if (!foundEntry) continue;
    const blockMatch  = line.match(/^(\s*)prompt_content\s*:\s*[|>][-+]?\s*$/);
    const inlineMatch = line.match(/^(\s*)prompt_content\s*:\s*(\S.+)$/);
    if (blockMatch)  { inContent = true; baseIndent = -1; continue; }
    if (inlineMatch) { return inlineMatch[2].trim().replace(/^["']|["']$/g, ''); }
    if (!inContent) continue;
    const lineIndent = line.match(/^(\s*)/)[1].length;
    if (baseIndent === -1) { if (line.trim() === '') continue; baseIndent = lineIndent; }
    if (line.trim() !== '' && lineIndent < baseIndent) break;
    result.push(line.length >= baseIndent ? line.slice(baseIndent) : line.trim());
  }
  if (foundEntry && inContent && result.length > 0) return result.join('\n').trim();
  return null;
}

const recommendPrompt = extractPromptContent(yamlContent, 'your_prompt_improver_name');
if (!recommendPrompt) {
  throw new Error('Prompt "your_prompt_improver_name" not found in YAML.');
}

return [{ json: {
  ...item,
  recommend_system_prompt: recommendPrompt
}}];

