const item = $input.first().json;
const raw  = item.text || item.output || '';

let rec = null;
try {
  const fence = raw.match(/```json\s*([\s\S]*?)```/);
  if (fence) rec = JSON.parse(fence[1].trim());
  else {
    const block = raw.match(/\{[\s\S]+\}/);
    if (block) rec = JSON.parse(block[0]);
  }
} catch(e) { rec = null; }

// chainLlm loses upstream fields — recover the full summary from static data
const sd      = $getWorkflowStaticData('global');
const summary = sd['pending_summary'] || {};
delete sd['pending_summary'];

return [{ json: {
  ...summary,
  recommend_issues:       rec?.issues_identified?.join(' | ')        || '-',
  recommend_improvements: rec?.recommended_improvements?.join(' | ') || '-',
  recommend_reasoning:    rec?.reasoning                              || '-'
}}];
